import{_ as o,c as e,o as t,ao as r}from"./chunks/framework.DtkG1rh0.js";const n="/images/leonardo.png",u=JSON.parse('{"title":"Leonardo免费使用教程","description":"","frontmatter":{"title":"Leonardo免费使用教程","date":"2022-11-05T15:06:25.000Z","tags":["软件分享"]},"headers":[],"relativePath":"posts/Leonardo免费使用教程.md","filePath":"posts/Leonardo免费使用教程.md"}'),s={name:"posts/Leonardo免费使用教程.md"};function i(d,a,l,h,_,p){return t(),e("div",null,a[0]||(a[0]=[r('<p><img src="'+n+'" alt="leonardo"></p><h1 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h1><p>Leonardo是专为windows二和一平板设计的位图绘画软件，它在windows平板以及数位屏上的书写延迟远远低于Clip Studio Paint（优动漫）、Photoshop等传统绘画软件。以下是免费使用流程</p><h1 id="流程" tabindex="-1">流程 <a class="header-anchor" href="#流程" aria-label="Permalink to &quot;流程&quot;">​</a></h1><h2 id="_1-下载安装软件本体" tabindex="-1">1. 下载安装软件本体 <a class="header-anchor" href="#_1-下载安装软件本体" aria-label="Permalink to &quot;1. 下载安装软件本体&quot;">​</a></h2><p>到官网下载。 我这里下载的是0.17.66版本，不保证更新版本可用。 安装位置为：C:\\Users\\【你的用户名】\\AppData\\Local\\Leonardo <strong>注意：AppData默认为隐藏文件夹</strong></p><h2 id="_2-下载注册表并打开" tabindex="-1">2. 下载注册表并打开 <a class="header-anchor" href="#_2-下载注册表并打开" aria-label="Permalink to &quot;2. 下载注册表并打开&quot;">​</a></h2><p>注册表下载地址：<strong>阿里云/s/j4ZG3YE7pVU</strong> 下载完成后打开。 点击确定完成注册。</p><h2 id="_3-阻止联网-重要" tabindex="-1">3. 阻止联网（重要） <a class="header-anchor" href="#_3-阻止联网-重要" aria-label="Permalink to &quot;3. 阻止联网（重要）&quot;">​</a></h2><p>在<strong>打开程序之前</strong>必须阻止软件目录下的xxx.win64.exe联网。 如果是surface pro x等CPU非Intel或AMD的电脑，也请阻止xxx.win64arm.exe联网。 方法不唯一，可以使用360，火绒等杀毒软件，也可以尝试glasswire等专门软件。 但是实测windows防火墙出入站规则无效，原因未知。</p><h2 id="_4-检查" tabindex="-1">4. 检查 <a class="header-anchor" href="#_4-检查" aria-label="Permalink to &quot;4. 检查&quot;">​</a></h2><p>打开软件，检查是否成功。如果出现<strong>登录弹窗</strong>，则为<strong>失败</strong>。 失败原因极有可能是阻止联网失败。 失败以后，请关闭软件，<strong>重新打开第二步中的注册表完成注册</strong>，尝试其他方式阻止软件联网。 没有弹出登录弹窗就成功了。</p><h3 id="仅供学习交流-请多多支持正版。" tabindex="-1">仅供学习交流，请多多支持正版。 <a class="header-anchor" href="#仅供学习交流-请多多支持正版。" aria-label="Permalink to &quot;仅供学习交流，请多多支持正版。&quot;">​</a></h3>',13)]))}const m=o(s,[["render",i]]);export{u as __pageData,m as default};
